import React from "react"
import Layout from "../components/_App/layout"
import Seo from "../components/_App/seo"
import Navbar from "../components/_App/Navbar"
import ExpertiseHero from "../components/Expertise/ExpertiseHero"
import Footer from "../components/_App/Footer"
import PageBanner from "../components/Common/PageBanner"
import Capabilities from "../components/Expertise/Capabilities"
import Approach from "../components/Expertise/Approach"

const ExpertisePage = () => {
  return (
    <Layout>
      <Navbar />

      <PageBanner
        pageTitle="Expertise"
        homePageText="Home"
        homePageUrl="/"
        activePageText="Expertise"
      />
      <ExpertiseHero />
      <Capabilities />
      <Approach />
      <Footer />
    </Layout>
  )
}

export const Head = () => (
  <Seo
    title="Expertise - AppNetWise"
    description="AppNetWise is a full-stack development company that builds modern web applications using cutting-edge technologies and best practices."
  />
)

export default ExpertisePage
